1. **Обнови класс BankAccount:**
```python
class BankAccount:
    def __init__(self, name, account_number, balance=0):
        self.name = name
        self.account_number = account_number
        self.balance = balance
        self.transactions = []  # История операций

    def deposit(self, amount):
        """Пополнить счёт."""
        try:
            amount = float(amount)
            if amount <= 0:
                return {"success": False, "message": "Сумма должна быть > 0"}

            self.balance += amount
            self.transactions.append({
                "type": "deposit",
                "amount": amount,
                "balance": self.balance
            })
            return {"success": True, "message": f"Пополнено: {amount} руб."}
        except ValueError:
            return {"success": False, "message": "Неверная сумма"}

    def withdraw(self, amount):
        """Снять деньги."""
        try:
            amount = float(amount)
            if amount <= 0:
                return {"success": False, "message": "Сумма должна быть > 0"}
            if amount > self.balance:
                return {"success": False, "message": "Недостаточно средств"}

            self.balance -= amount
            self.transactions.append({
                "type": "withdraw",
                "amount": amount,
                "balance": self.balance
            })
            return {"success": True, "message": f"Снято: {amount} руб."}
        except ValueError:
            return {"success": False, "message": "Неверная сумма"}

    def show_transactions(self):
        """Показать историю операций."""
        print(f"\n📜 История операций ({self.name}):")
        if len(self.transactions) == 0:
            print("  Операций пока нет")
            return

        for i, transaction in enumerate(self.transactions, 1):
            op_type = "📥 Пополнение" if transaction["type"] == "deposit" else "📤 Снятие"
            print(f"  {i}. {op_type}: {transaction['amount']} руб. | Баланс: {transaction['balance']} руб.")
```

