def safe_load_account(filename):
    """Безопасная загрузка счёта с полной проверкой."""
    try:
        with open(filename, "r", encoding="utf-8") as file:
            data = json.load(file)

        # Валидация обязательных полей
        required_fields = ["name", "account_number", "balance", "transactions"]
        for field in required_fields:
            if field not in data:
                return {"success": False, "message": f"Отсутствует поле: {field}"}

        # Валидация типов
        if not isinstance(data["balance"], (int, float)):
            return {"success": False, "message": "Баланс должен быть числом"}

        if data["balance"] < 0:
            return {"success": False, "message": "Баланс не может быть отрицательным"}

        # Создание account
        account = BankAccount(
            name=data["name"],
            account_number=data["account_number"],
            balance=data["balance"]
        )
        account.transactions = data["transactions"]

        return {"success": True, "account": account}

    except FileNotFoundError:
        return {"success": False, "message": f"Файл {filename} не найден"}

    except json.JSONDecodeError:
        return {"success": False, "message": "Файл повреждён (невалидный JSON)"}

    except Exception as e:
        return {"success": False, "message": f"Неожиданная ошибка: {e}"}

# Использование
result = safe_load_account("ACC001.json")
if result["success"]:
    account = result["account"]
    print(f"✅ Счёт загружен: {account}")
else:
    print(f"❌ {result['message']}")
```

