@staticmethod
def load(filename="bank_data.json"):
    """Загрузить банк из файла."""
    try:
        with open(filename, "r", encoding="utf-8") as file:
            data = json.load(file)

        bank = Bank()
        bank.next_account_number = data["next_account_number"]

        for acc_data in data["accounts"]:
            account = BankAccount(
                name=acc_data["name"],
                account_number=acc_data["account_number"],
                balance=acc_data["balance"]
            )
            account.transactions = acc_data["transactions"]
            bank.accounts.append(account)

        return bank

    except FileNotFoundError:
        print(f"Файл {filename} не найден, создан новый банк")
        return Bank()
    except Exception as e:
        print(f"Ошибка загрузки: {e}")
        return Bank()

